+@page "/notifications"
+@rendermode @(new InteractiveServerRenderMode(prerender: true))
+@using BlazorNotifications.Services
+@inject NotificationService NotificationService
+@implements IDisposable
+
+<PageTitle>Notifications</PageTitle>
+
