+{
+    <p><em>No notifications yet.</em></p>
+}
+else
+{
+    <ul class="list-group">
+        @foreach (var notification in _notifications.OrderByDescending(n => n.Timestamp))
+        {
+            <li class="list-group-item">
+                <strong>@notification.Message</strong>
+                <br />
+                <small class="text-muted">@notification.Timestamp.ToString("g")</small>
+            </li>
+        }
+    </ul>
+}
+
+@code {
+    private List<Notification> _notifications = new();
+    private CancellationTokenSource? _cts;
+    private int _lastSeenId;
+
+    protected override void OnInitialized()
+    {
+        // Load initial notifications during prerender (SSR) and interactive init.
+        // This ensures the first server-rendered HTML already contains the data.
+        _notifications = NotificationService.GetAll();
+        _lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;
+    }
+
+    protected override void OnAfterRender(bool firstRender)
+    {
+        if (firstRender)
+        {
+            // OnAfterRender only fires in interactive mode (not during static SSR prerender).
+            // This is the safe place to start the polling loop.
+            _cts = new CancellationTokenSource();
+            _ = PollForNotificationsAsync(_cts.Token);
+        }
+    }
+
+    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
+    {
+        while (!cancellationToken.IsCancellationRequested)
+        {
+            await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);
+
+            var newItems = NotificationService.GetSince(_lastSeenId);
+            if (newItems.Count > 0)
+            {
+                _notifications.AddRange(newItems);
+                _lastSeenId = newItems.Max(n => n.Id);
+                await InvokeAsync(StateHasChanged);
+            }
+        }
+    }
+
+    public void Dispose()
+    {
+        // Clean cancellation — stops the polling loop with no leaked tasks.
+        _cts?.Cancel();
+        _cts?.Dispose();
+    }
+}
